11	const dataDirectory = join(process.cwd(), 'data');
12	const postsFile = join(dataDirectory, 'posts.json');
13	
14	async function readPostsFromDisk() {
15	  try {
16	    const file = await readFile(postsFile, 'utf8');
17	    return JSON.parse(file) as Post[];
18	  } catch (error) {
19	    if ((error as NodeJS.ErrnoException).code === 'ENOENT') {
20	      return [];
21	    }
22	
23	    throw error;
24	  }
25	}
