35	export async function createPostRecord(title: string) {
36	  const posts = await readPostsFromDisk();
37	  const post: Post = {
38	    id: crypto.randomUUID(),
39	    title,
40	    createdAt: new Date().toISOString(),
41	  };
42	
43	  await mkdir(dataDirectory, { recursive: true });
44	  await writeFile(postsFile, JSON.stringify([post, ...posts], null, 2));
45	
46	  return post;
47	}

